class Solution:
    def customSortString(self, order: str, s: str) -> str:
        cnt = Counter(s)
        ans = []
        for c in order:
            ans.append(c * cnt[c]); del cnt[c]
        for c in sorted(cnt):
            ans.append(c * cnt[c])
        return "".join(ans)

