class Solution {
public:
    string customSortString(string order, string s) {
        int cnt[26]={}; for(char c:s) cnt[c-'a']++;
        string ans;
        for(char c:order) while(cnt[c-'a']--) ans.push_back(c);
        for(int i=0;i<26;i++) while(cnt[i]--) ans.push_back(i+'a');
        return ans;
    }
};

